import 'dart:convert';
import 'dart:typed_data';

/// Auto-generated sprite data extracted from JSX prototype.
/// Each hero's sprite as base64 PNG (90x110px).
class HeroSprites {
  static const Map<String, String> _data = {
    'shaolin': '',
    'templar': '',
    'ninja': '',
    'sumo': '',
    'kungfu': '',
    'samurai': '',
    'gladiator': '',
    'monk': '',
    'viking': '',
    'capoeira': '',
    'spartan': '',
    'muaythai': '',
    'taichi': '',
    'wrestler': '',
    'pirate': '',
    'amazon': '',
    'shaman': '',
    'berserker': '',
    'wushu': '',
    'mongol': '',
  };

  static Uint8List? getBytes(String heroId) {
    final b64 = _data[heroId];
    if (b64 == null) return null;
    return base64Decode(b64);
  }

  static List<String> get allHeroIds => _data.keys.toList();
}